import React, { useState } from 'react';
import { Mail, Lock, User, Ruler, Palette, ChevronRight, ChevronLeft, Camera, Sparkles, Shirt } from 'lucide-react';
import './AuthPage.css';

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '', email: '', password: '', gender: '',
    height: '', weight: '', skinTone: '',
    chest: '', waist: '', hips: ''
  });

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const nextStep = () => setStep(step + 1);
  const prevStep = () => setStep(step - 1);

  return (
    <div className="auth-master-container">
      <div className="auth-glass-card">
        
        {/* Left Side: Visual Experience */}
        <div className="auth-visual-pane">
          <div className="visual-overlay"></div>
          <img 
            src="https://images.unsplash.com/photo-1551232864-3f0890e580d9?q=80&w=1000&auto=format&fit=crop" 
            alt="Fashion AI" 
            className="auth-img"
          />
          <div className="visual-content">
            <div className="auth-logo">
              <Sparkles className="logo-sparkle" />
              <span>StyleMirror</span>
            </div>
            <h2>{isLogin ? "Welcome Back to the Future." : "Start Your Style Journey."}</h2>
            <p>Your digital twin is waiting to try on the latest trends.</p>
          </div>
        </div>

        {/* Right Side: Form Content */}
        <div className="auth-form-pane">
          <div className="form-header">
            <h1>{isLogin ? "Sign In" : "Create Account"}</h1>
            <p>{isLogin ? "Enter your credentials to access your wardrobe." : "Step " + step + " of 2: Personalize your AI profile"}</p>
          </div>

          <form onSubmit={(e) => e.preventDefault()} className="auth-form">
            {isLogin ? (
              /* LOGIN FIELDS */
              <div className="fade-in">
                <div className="input-group">
                  <Mail className="input-icon" size={20} />
                  <input type="email" placeholder="Email Address" name="email" required />
                </div>
                <div className="input-group">
                  <Lock className="input-icon" size={20} />
                  <input type="password" placeholder="Password" name="password" required />
                </div>
                <span className="forgot-pass">Forgot Password?</span>
              </div>
            ) : (
              /* SIGNUP STEPS */
              <div className="fade-in">
                {step === 1 ? (
                  <div className="step-fields">
                    <div className="input-group">
                      <User className="input-icon" size={20} />
                      <input type="text" placeholder="Full Name" name="name" onChange={handleInputChange} />
                    </div>
                    <div className="input-group">
                      <Mail className="input-icon" size={20} />
                      <input type="email" placeholder="Email Address" name="email" onChange={handleInputChange} />
                    </div>
                    <div className="input-group">
                      <Lock className="input-icon" size={20} />
                      <input type="password" placeholder="Create Password" name="password" onChange={handleInputChange} />
                    </div>
                  </div>
                ) : (
                  <div className="step-fields grid-fields">
                    <div className="input-group"><Ruler className="input-icon" size={18} /><input type="number" placeholder="Height (cm)" name="height" /></div>
                    <div className="input-group"><User className="input-icon" size={18} /><input type="number" placeholder="Weight (kg)" name="weight" /></div>
                    <div className="input-group"><Palette className="input-icon" size={18} /><input type="text" placeholder="Skin Tone" name="skinTone" /></div>
                    <div className="input-group"><Shirt size={18} className="input-icon"/><input type="text" placeholder="Chest (cm)" name="chest" /></div>
                  </div>
                )}
              </div>
            )}

            <div className="auth-actions">
              {!isLogin && step === 1 ? (
                <button type="button" className="btn-auth-primary" onClick={nextStep}>
                  Next Details <ChevronRight size={20} />
                </button>
              ) : (
                <div className="action-row">
                  {!isLogin && <button type="button" className="btn-back" onClick={prevStep}><ChevronLeft size={20} /></button>}
                  <button type="submit" className="btn-auth-primary">
                    {isLogin ? "Sign In" : "Complete Registration"}
                  </button>
                </div>
              )}
            </div>
          </form>

          <div className="auth-footer">
            <p>
              {isLogin ? "New to StyleMirror?" : "Already have an account?"}
              <span onClick={() => {setIsLogin(!isLogin); setStep(1);}}>
                {isLogin ? " Create Account" : " Sign In"}
              </span>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
